```kql
// ─── union de tables du même workspace ───
union SecurityEvent, Syslog, CommonSecurityLog
| where TimeGenerated > ago(1h)
| summarize Count=count() by Type
| sort by Count desc

// ─── Cross-workspace queries ───
// Requêtes sur plusieurs workspaces Sentinel
union
    workspace("workspace-prod").SecurityEvent,
    workspace("workspace-dev").SecurityEvent
| where TimeGenerated > ago(1h)
| where EventID == 4625
| summarize Count=count() by IpAddress, workspace=...

// ─── External data : IOC depuis URL ou blob ───
// Charger des IOC depuis une source externe
let ExternalIOCs = externaldata(IP:string, Threat:string)
    [@"https://raw.githubusercontent.com/example/ioc-feed/main/ips.csv"]
    with (format="csv", ignoreFirstRecord=true);

SigninLogs
| join kind=inner ExternalIOCs on $left.IPAddress == $right.IP
| project TimeGenerated, UserPrincipalName, IPAddress, Threat

// ─── materialize() : mettre en cache une sous-requête ───
// Évite d'évaluer la même requête deux fois
let CachedFails = materialize(
    SecurityEvent
    | where TimeGenerated > ago(1h)
    | where EventID == 4625
    | project TimeGenerated, IpAddress, Account
);

CachedFails
| summarize FailCount=count() by IpAddress
| join kind=inner (
    CachedFails
    | summarize Accounts=make_set(Account) by IpAddress
) on IpAddress
| sort by FailCount desc
```

**En production, les requêtes KQL doivent être optimisées pour ne pas surcharger le workspace :**

```kql
// ─── RÈGLES D'OPTIMISATION ───

// 1. Filtrer tôt par TimeGenerated (utilise l'index)
// BON :
SecurityEvent
| where TimeGenerated > ago(1h)  // ← Premier filtre
| where EventID == 4625

// MAUVAIS :
SecurityEvent
| where EventID == 4625
| where TimeGenerated > ago(1h)  // ← Trop tard, scanne toute la table

// 2. Filtrer par table avant de joindre
// BON :
let Fails = SecurityEvent
    | where TimeGenerated > ago(1h)  // Filtrer d'abord
    | where EventID == 4625
    | summarize Count=count() by IpAddress;  // Réduire ensuite

// 3. has vs contains : has est plus rapide (index inversé)
// BON :
Syslog | where SyslogMessage has "Failed"
// MOINS BON :
Syslog | where SyslogMessage contains "Failed"

// 4. project tôt pour réduire les colonnes
SecurityEvent
| where TimeGenerated > ago(1h)
| where EventID == 4625
| project TimeGenerated, IpAddress, Account  // ← Réduire avant summarize
| summarize Count=count() by IpAddress

// 5. take vs limit : identiques, prendre les résultats tôt
SecurityEvent
| where EventID == 4625
| take 1000  // Pas besoin de trier 10 millions de lignes

// 6. Éviter les fonctions dans where quand possible
// MAUVAIS : evaluate une fonction sur chaque ligne
// SecurityEvent | where strlen(Account) > 20
// BON : si possible, reformuler
// SecurityEvent | where Account matches regex @".{21,}"
```
